/**
 * Generate runtime JavaScript for the bundle.
 * @param {string} bundleId - Bundle ID
 * @param {Object} lens - LENS state
 * @param {Object} [skin] - SKIN definition (for dark mode)
 * @param {boolean} [prefersDark=false] - Initial dark mode state
 */
function generateRuntimeJS(bundleId, lens, skin, prefersDark = false) {
  return `
(function() {
  'use strict';
  
  const USX = {
    bundleId: '${bundleId}',
    lens: ${JSON.stringify(lens)},
    darkMode: ${prefersDark},
    
    // Event handler
    handleEvent(widgetId, eventType, event) {
      const widget = document.querySelector(\`[data-widget-id="\${widgetId}"]\`);
      if (!widget) return;
      
      // Dispatch custom event for external listeners
      const detail = { widgetId, eventType, event, lens: this.lens };
      document.dispatchEvent(new CustomEvent('usx:event', { detail }));
      
      // Log for debugging
      if (window.__USX_DEBUG) {
        console.log('[USX Event]', widgetId, eventType, event);
      }
    },
    
    // Update a LENS variable and re-render
    setVariable(path, value) {
      const keys = path.split('.');
      let current = this.lens;
      for (let i = 0; i < keys.length - 1; i++) {
        if (!current[keys[i]]) current[keys[i]] = {};
        current = current[keys[i]];
      }
      current[keys[keys.length - 1]] = value;
      
      // Dispatch update event
      document.dispatchEvent(new CustomEvent('usx:update', {
        detail: { path, value, lens: this.lens }
      }));
    },
    
    // Get a LENS variable
    getVariable(path) {
      return path.split('.').reduce((obj, key) => 
        obj && obj[key] !== undefined ? obj[key] : undefined, this.lens);
    },
    
    // Toggle dark mode
    toggleDarkMode() {
      this.darkMode = !this.darkMode;
      const root = document.documentElement;
      const toggle = document.getElementById('dark-toggle');
      
      if (this.darkMode) {
        root.classList.add('usx-dark-mode');
        if (toggle) toggle.textContent = '☀️';
      } else {
        root.classList.remove('usx-dark-mode');
        if (toggle) toggle.textContent = '🌙';
      }
      
      // Dispatch dark mode event
      document.dispatchEvent(new CustomEvent('usx:darkmode', {
        detail: { darkMode: this.darkMode }
      }));
    },
    
    // Check if dark mode is active
    isDarkMode() {
      return this.darkMode || document.documentElement.classList.contains('usx-dark-mode');
    }
  };
  
  // Expose globally
  window.usx = USX;
  
  // Apply initial dark mode if set
  if (${prefersDark}) {
    document.documentElement.classList.add('usx-dark-mode');
  }
  
  // Debug mode
  if (window.location.hash === '#debug') {
    window.__USX_DEBUG = true;
    console.log('[USX] Bundle:', '${bundleId}');
    console.log('[USX] LENS:', USX.lens);
    console.log('[USX] Dark Mode:', USX.darkMode);
  }
})();
`;
}

